INSERT INTO public.exercises(course_id,module_id,slug,title,exercise_type,brief_md,starter_files,expected_result_md,hints,solution_md,order_index,estimated_minutes,is_published)
SELECT c.id,m.id,e.slug,e.title,e.exercise_type,e.brief_md,e.starter_files,e.expected_result_md,e.hints,e.solution_md,0,e.estimated_minutes,FALSE
FROM course_row c JOIN module_rows m ON TRUE JOIN exercise_seed e ON e.module_order=m.order_index
ON CONFLICT(course_id,slug) DO UPDATE SET module_id=EXCLUDED.module_id,title=EXCLUDED.title,exercise_type=EXCLUDED.exercise_type,brief_md=EXCLUDED.brief_md,starter_files=EXCLUDED.starter_files,expected_result_md=EXCLUDED.expected_result_md,hints=EXCLUDED.hints,solution_md=EXCLUDED.solution_md,estimated_minutes=EXCLUDED.estimated_minutes,is_published=FALSE;

WITH c AS (SELECT id FROM public.courses WHERE slug='data-engineering-python-sql'), resources(module_order,slug,title,summary,content_md,ord) AS (VALUES (0,'python-files','Python pathlib et fichiers','Documentation officielle Python','# Ressource officielle\n\n[Python pathlib et fichiers](https://docs.python.org/3/library/pathlib.html)',0),(1,'python-requests','Requests','Documentation Requests','# Ressource officielle\n\n[Requests](https://requests.readthedocs.io/)',1),(2,'postgres-ddl','PostgreSQL DDL','Documentation PostgreSQL','# Ressource officielle\n\n[PostgreSQL DDL](https://www.postgresql.org/docs/current/ddl.html)',2),(3,'parquet','Apache Parquet','Documentation du format Parquet','# Ressource officielle\n\n[Apache Parquet](https://parquet.apache.org/docs/)',3),(4,'postgres-insert','PostgreSQL INSERT','Documentation INSERT et ON CONFLICT','# Ressource officielle\n\n[PostgreSQL INSERT](https://www.postgresql.org/docs/current/sql-insert.html)',4),(5,'data-quality','Great Expectations concepts','Référence qualité des données','# Ressource officielle\n\n[Great Expectations concepts](https://docs.greatexpectations.io/)',5),(6,'dimensional-modeling','Modélisation dimensionnelle','Référence dbt sur les marts','# Ressource officielle\n\n[Modélisation dimensionnelle](https://docs.getdbt.com/best-practices/how-we-structure/4-marts)',6),(7,'dbt-docs','dbt Developer Hub','Documentation officielle dbt','# Ressource officielle\n\n[dbt Developer Hub](https://docs.getdbt.com/)',7),(8,'airflow-docs','Apache Airflow','Documentation officielle Airflow','# Ressource officielle\n\n[Apache Airflow](https://airflow.apache.org/docs/)',8),(9,'docker-docs','Docker Documentation','Documentation officielle Docker','# Ressource officielle\n\n[Docker Documentation](https://docs.docker.com/)',9),(10,'open-telemetry','OpenTelemetry','Documentation observabilité','# Ressource officielle\n\n[OpenTelemetry](https://opentelemetry.io/docs/)',10),(11,'github-actions','GitHub Actions','Documentation officielle GitHub Actions','# Ressource officielle\n\n[GitHub Actions](https://docs.github.com/actions)',11))
INSERT INTO public.theory_resources(course_id,module_id,slug,title,summary,content_md,resource_type,order_index,is_published)
SELECT c.id,m.id,r.slug,r.title,r.summary,r.content_md,'reference',r.ord,FALSE
FROM c JOIN resources r ON TRUE JOIN public.modules m ON m.course_id=c.id AND m.order_index=r.module_order
ON CONFLICT(course_id,slug) DO UPDATE SET module_id=EXCLUDED.module_id,title=EXCLUDED.title,summary=EXCLUDED.summary,content_md=EXCLUDED.content_md,resource_type=EXCLUDED.resource_type,order_index=EXCLUDED.order_index,is_published=FALSE;

DO $$
DECLARE exercise_count INT; resource_count INT; module_exercises INT; published_exercises INT; published_resources INT; invalid_types INT;
BEGIN
 SELECT COUNT(*),COUNT(DISTINCT e.module_id),COUNT(*) FILTER (WHERE e.is_published),COUNT(*) FILTER (WHERE e.exercise_type NOT IN ('guided','debug','challenge'))
 INTO exercise_count,module_exercises,published_exercises,invalid_types
 FROM public.exercises e JOIN public.courses c ON c.id=e.course_id WHERE c.slug='data-engineering-python-sql';
 SELECT COUNT(*),COUNT(*) FILTER (WHERE r.is_published) INTO resource_count,published_resources
 FROM public.theory_resources r JOIN public.courses c ON c.id=r.course_id WHERE c.slug='data-engineering-python-sql';
 IF exercise_count<>12 OR module_exercises<>12 OR resource_count<>12 OR published_exercises<>0 OR published_resources<>0 OR invalid_types<>0 THEN
  RAISE EXCEPTION 'Chantier 4 Data Engineering incomplet: exercices %, modules %, ressources %, exercices publiés %, ressources publiées %, types invalides %',exercise_count,module_exercises,resource_count,published_exercises,published_resources,invalid_types;
 END IF;
END $$;
